import{c as n,Q as a,j as r,m as t}from"./chunks/framework.BXc4yaFE.js";const d=JSON.parse('{"title":"The Third Evolution: Why Harness Engineering Replaced Prompting in 2026","description":"","frontmatter":{"url":"https://www.epsilla.com/blogs/harness-engineering-evolution-prompt-context-autonomous-agents","title":"The Third Evolution: Why Harness Engineering Replaced Prompting in 2026","author":"Isabella (Epsilla)","archived":"2026-05-27T00:00:00.000Z","domain":"epsilla.com","published":"2026-03-25T00:00:00.000Z","tags":["harness-engineering","prompt-engineering","context-engineering","autonomous-agents","llm-agents","enterprise-ai"],"word_count":"約 1,200 字"},"headers":[],"relativePath":"research/ai-articles/2026-03-25-epsilla-harness-engineering-evolution.md","filePath":"research/ai-articles/2026-03-25-epsilla-harness-engineering-evolution.md","lastUpdated":1779901665000}'),i={name:"research/ai-articles/2026-03-25-epsilla-harness-engineering-evolution.md"};function o(s,e,l,h,g,p){return a(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="the-third-evolution-why-harness-engineering-replaced-prompting-in-2026" tabindex="-1">The Third Evolution: Why Harness Engineering Replaced Prompting in 2026 <a class="header-anchor" href="#the-third-evolution-why-harness-engineering-replaced-prompting-in-2026" aria-label="Permalink to &quot;The Third Evolution: Why Harness Engineering Replaced Prompting in 2026&quot;">​</a></h1><blockquote><p><strong>來源</strong>：<a href="https://www.epsilla.com/blogs/harness-engineering-evolution-prompt-context-autonomous-agents" target="_blank" rel="noreferrer">epsilla.com</a><strong>作者</strong>：Isabella（Epsilla） <strong>發布日期</strong>：2026-03-25 <strong>收錄日期</strong>：2026-05-27</p></blockquote><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>本文記錄 AI 工程實踐的演進歷程，論證業界已從優化單一 prompt 轉移到為自主 agents 建構完整的運作環境。核心論點：「Agents 不難；難的是 Harness。」</p><h2 id="三代演進歷程" tabindex="-1">三代演進歷程 <a class="header-anchor" href="#三代演進歷程" aria-label="Permalink to &quot;三代演進歷程&quot;">​</a></h2><h3 id="第一代-prompt-engineering-2022–2024" tabindex="-1">第一代：Prompt Engineering（2022–2024） <a class="header-anchor" href="#第一代-prompt-engineering-2022–2024" aria-label="Permalink to &quot;第一代：Prompt Engineering（2022–2024）&quot;">​</a></h3><p>專注於製作最佳化的單一指令，技術包括 few-shot learning 和 chain-of-thought prompting。工程師的核心工作是「找到正確的詞語」。</p><h3 id="第二代-context-engineering-2025" tabindex="-1">第二代：Context Engineering（2025） <a class="header-anchor" href="#第二代-context-engineering-2025" aria-label="Permalink to &quot;第二代：Context Engineering（2025）&quot;">​</a></h3><p>認識到模型需要動態建構的 context window，包含相關文件、對話歷史和工具定義。重點從「如何說」轉移到「給什麼資訊」。</p><h3 id="第三代-harness-engineering-2026" tabindex="-1">第三代：Harness Engineering（2026） <a class="header-anchor" href="#第三代-harness-engineering-2026" aria-label="Permalink to &quot;第三代：Harness Engineering（2026）&quot;">​</a></h3><p>系統層面的架構設計，涵蓋 agents 的完整工作流程、約束條件、回饋迴路和生命週期管理。重點從「說什麼」轉移到「建立什麼環境」。</p><h2 id="關鍵效能數據" tabindex="-1">關鍵效能數據 <a class="header-anchor" href="#關鍵效能數據" aria-label="Permalink to &quot;關鍵效能數據&quot;">​</a></h2><p><strong>最重要的實驗結果</strong>：使用<strong>相同模型、相同資料、相同 prompt</strong>，一個團隊透過僅修改 runtime 環境，將程式設計 benchmark 成功率從 <strong>42% 提升至 78%</strong>。</p><p>唯一的變數是包裹模型的 shell——即 harness 本身。</p><p>此外，Anthropic 展示了在管理環境中採用結構化迭代方法，儘管成本更高，卻能產生更優異的結果。</p><h2 id="harness-核心概念" tabindex="-1">Harness 核心概念 <a class="header-anchor" href="#harness-核心概念" aria-label="Permalink to &quot;Harness 核心概念&quot;">​</a></h2><p>Mitchell Hashimoto 的定義：「工程化解決方案，防止 agent 錯誤重複發生。」</p><p>關鍵洞見：「Agents 不難；Harness 才難。」</p><h2 id="真實案例驗證" tabindex="-1">真實案例驗證 <a class="header-anchor" href="#真實案例驗證" aria-label="Permalink to &quot;真實案例驗證&quot;">​</a></h2><h3 id="openai-codex-團隊" tabindex="-1">OpenAI Codex 團隊 <a class="header-anchor" href="#openai-codex-團隊" aria-label="Permalink to &quot;OpenAI Codex 團隊&quot;">​</a></h3><p>五個月內在 1,500 個 pull requests 中生成約<strong>一百萬行</strong>生產程式碼，零人工撰寫程式碼。</p><p>核心 harness 原則：</p><ol><li><strong>Repository is truth</strong>：repository 是 agent 唯一的事實來源，不假設外部知識</li><li><strong>Agent-readable code</strong>：程式碼必須對 agent 可讀（不只對人類），需有清晰一致的結構和詳細 comment</li><li><strong>Linter-enforced constraints</strong>：架構約束由 linter 強制執行，而非依賴 prompt——建立一個讓違反規則成為不可能的系統</li><li><strong>Incremental autonomy</strong>：逐步擴大自主權範圍</li></ol><h3 id="stripe-minions" tabindex="-1">Stripe Minions <a class="header-anchor" href="#stripe-minions" aria-label="Permalink to &quot;Stripe Minions&quot;">​</a></h3><p>「Minions」機群每週合併超過 <strong>1,300 個 pull requests</strong>，採用「Blueprint」編排系統，分離確定性節點與 agentic 節點，並有嚴格的兩次失敗升級規則。</p><h2 id="anthropic-的評估者模型" tabindex="-1">Anthropic 的評估者模型 <a class="header-anchor" href="#anthropic-的評估者模型" aria-label="Permalink to &quot;Anthropic 的評估者模型&quot;">​</a></h2><p>Anthropic 識別的關鍵限制：<strong>模型無法可靠地自我評估其工作</strong>。</p><p>解決方案：實作受 GAN 架構啟發的獨立 Generator 和 Evaluator agents，評估者使用 Playwright 等工具進行端對端測試。</p><h2 id="約束的悖論" tabindex="-1">約束的悖論 <a class="header-anchor" href="#約束的悖論" aria-label="Permalink to &quot;約束的悖論&quot;">​</a></h2><p>限制解決方案空間看似矛盾，實際上能提升生產力：</p><ul><li>防止探索無效路徑</li><li>強迫更快收斂至正確解</li></ul><h2 id="epsilla-的-semantic-graph-解決方案" tabindex="-1">Epsilla 的 Semantic Graph 解決方案 <a class="header-anchor" href="#epsilla-的-semantic-graph-解決方案" aria-label="Permalink to &quot;Epsilla 的 Semantic Graph 解決方案&quot;">​</a></h2><p>Epsilla 提出企業級 harness 基礎設施，提供：</p><table tabindex="0"><thead><tr><th>功能</th><th>說明</th></tr></thead><tbody><tr><td><strong>結構性約束</strong></td><td>防止幻覺（hallucination）</td></tr><tr><td><strong>持久記憶</strong></td><td>編碼回饋迴路</td></tr><tr><td><strong>可擴展的非同步互動</strong></td><td>支援 Agent-as-a-Service (AaaS) 部署</td></tr></tbody></table><h2 id="核心結論" tabindex="-1">核心結論 <a class="header-anchor" href="#核心結論" aria-label="Permalink to &quot;核心結論&quot;">​</a></h2><p>Harness engineering 解決了前兩代範式無法處理的根本問題：「AI 模型無法可靠評估自身工作」。答案不是更好的 prompt，而是更好的環境設計。</p><hr><p><em>相關 Epsilla 文章：</em></p><ul><li><em><a href="https://www.epsilla.com/blogs/2026-03-12-harness-engineering" target="_blank" rel="noreferrer">Harness Engineering: Why the Focus is Shifting from Models to Agent Control Systems</a></em></li><li><em><a href="https://www.epsilla.com/blogs/anthropic-harness-engineering-multi-agent-gan-architecture" target="_blank" rel="noreferrer">The GAN-Style Agent Loop: Deconstructing Anthropic&#39;s Harness Architecture</a></em></li></ul>',40)])])}const u=n(i,[["render",o]]);export{d as __pageData,u as default};
